mapper.insert:

select coalesce(max(hist_seq) + 1 ,1) as hist_seq
from esg.tb_safety_checklist_history

insert into esg.tb_safety_checklist_history (
    write_year,
    hist_seq,
    std_eq_id,
    inspection_cycle,
    created_at,
    created_by,
    comp_id
)
select
    #{writeYear}
    , #{histSeq}
    , #{stdEqId}
    , #{inspectionCycle}
    , now()
    , #{createdBy}
    , #{compId}
where #{inspectionCycle} is not null
    and #{inspectionCycle} != ''
    and not exists (
        select 1
        from (
            select inspection_cycle
            from esg.tb_safety_checklist_history
            where write_year = #{writeYear}
                and std_eq_id = #{stdEqId}
                and comp_id = #{compId}
            order by created_at DESC
            limit 1
        ) latest
    where latest.inspection_cycle = #{inspectionCycle}
)

